mapper.select:
select c.*, t.teacher_name as teacherName, t.college_id as collegeId, co.college_name as collegeName from course c
left join teacher t on c.teacher_id = t.teacher_id
left join college co on t.college_id = co.id


        and course_name like concat('%',#{courseName},'%')


        and t.teacher_name like concat('%',#{teacherName},'%')


        and c.teacher_id = #{teacherId}


        and c.college_id = #{collegeId}


        and c.credit = #{credit}


        and c.class_hour = #{classHour}


        and c.max_student <= #{maxStudent}
